  function missionHistoryKey(sessionId, skill){
    return `S${sessionId}_${skill}`;
  }

  function pickMissionVariant(sessionId, skill){
    const sid = Number(sessionId || state.currentSession || 1);
    state.skillBankHistory = state.skillBankHistory || {};
    const hkey = missionHistoryKey(sid, skill);
    const recent = state.skillBankHistory[hkey] || [];
    const comboKey = `${hkey}_combos`;
    const recentCombos = state.skillBankHistory[comboKey] || [];

    const topics = EAP_REPLAY_TOPIC_BANK[sid] || EAP_REPLAY_TOPIC_BANK[1];
    const templates = missionTemplatesFor(skill, sid);
    const combos = [];
    topics.forEach((t, topicIdx)=>{
      templates.forEach((v, variantIdx)=>{
        combos.push({topicIdx, variantIdx, t, v, combo:`s${sid}_${skill}_topic${topicIdx}_var${variantIdx}`});
      });
    });
    let pool = combos.filter(x=>!recentCombos.includes(x.combo));
    if(!pool.length) pool = combos.slice();
    const strong = pool.filter(x=>!recent.includes(`topic${x.topicIdx}`) && !recent.includes(`var${x.variantIdx}`));
    if(strong.length) pool = strong;
    const chosen = pool[Math.floor(Math.random()*pool.length)];

    state.skillBankHistory[hkey] = [`topic${chosen.topicIdx}`, `var${chosen.variantIdx}`].concat(recent).slice(0,24);
    state.skillBankHistory[comboKey] = [chosen.combo].concat(recentCombos).slice(0,160);
    saveState();

    const variant = Object.assign({}, chosen.v);
    if(skill === 'Reading') variant.q = readingQuestionSetForSession(sid);
    return {
      session:sid,
      skill,
      topic:chosen.t[0],
      passage:chosen.t[1],
      variant,
      topicIndex:chosen.topicIdx,
      variantIndex:chosen.variantIdx,
      combo:chosen.combo
    };
  }

  function missionBankCount(){
    const topicCount = Object.values(SESSION_TOPIC_VARIANTS).reduce((sum, arr)=>sum+arr.length, 0);
    const perSkill = {
      Reading:Object.keys(SESSION_TOPIC_VARIANTS).length * SKILL_MISSION_VARIANTS.Reading.templates.length * 6,
      Writing:Object.keys(SESSION_TOPIC_VARIANTS).length * SKILL_MISSION_VARIANTS.Writing.prompts.length * 6,
      Listening:Object.keys(SESSION_TOPIC_VARIANTS).length * SKILL_MISSION_VARIANTS.Listening.tasks.length * 6,
      Speaking:Object.keys(SESSION_TOPIC_VARIANTS).length * SKILL_MISSION_VARIANTS.Speaking.prompts.length * 6
    };
    return { topics:topicCount, perSkill, estimatedCombinations: perSkill.Reading + perSkill.Writing + perSkill.Listening + perSkill.Speaking };
  }



  function skillTemplateDuplicateAudit(){
    const groups = {
      Reading:SKILL_MISSION_VARIANTS.Reading.templates.map(x => ({ id:x.id, text:(x.q || []).join(' | ') })),
      Writing:SKILL_MISSION_VARIANTS.Writing.prompts.map(x => ({ id:x.type, text:[x.title,x.target,x.instruction].join(' | ') })),
      Listening:SKILL_MISSION_VARIANTS.Listening.tasks.map(x => ({ id:x.id, text:[x.focus,x.ask].join(' | ') })),
      Speaking:SKILL_MISSION_VARIANTS.Speaking.prompts.map(x => ({ id:x.id, text:[x.title,x.instruction].join(' | ') }))
    };
    const normalize = s => String(s || '').toLowerCase().replace(/[^a-z0-9 ]+/g,' ').replace(/\s+/g,' ').trim();
    const result = {};
    Object.keys(groups).forEach(skill => {
      const ids = {};
      const texts = {};
      groups[skill].forEach(x => {
        ids[x.id] = (ids[x.id] || 0) + 1;
        texts[normalize(x.text)] = (texts[normalize(x.text)] || 0) + 1;
      });
      result[skill] = {
        count:groups[skill].length,
        duplicateIds:Object.keys(ids).filter(k => ids[k] > 1),
        duplicateTexts:Object.keys(texts).filter(k => texts[k] > 1)
      };
    });
    return result;
  }


  function skillTextForSession(s){
    const topicMap = {
      1:['academic goal setting','Many students study English without a clear academic purpose. A useful EAP plan identifies a target skill, a practice strategy, and a way to review progress.'],
      2:['academic vocabulary','Academic vocabulary helps students understand lectures, textbooks, and research articles. Students should learn words in context and review how each word functions.'],
      3:['main idea reading','Effective readers identify the writer’s main idea, separate it from supporting details, and check how each sentence contributes to the paragraph.'],
      4:['keywords and signal words','Signal words such as however, therefore, and for example help readers follow relationships between ideas in reading and listening.'],
      5:['critical reading','Critical readers examine claims, evidence, source credibility, date, and possible bias before using information in academic work.'],
      6:['summarizing','A good summary keeps the original meaning but expresses the key ideas briefly in the student’s own words.'],
      7:['academic tone','Academic tone is formal, precise, and cautious. Writers should avoid casual expressions and unsupported claims.'],
      8:['integrated academic review','Academic English requires reading sources, identifying evidence, summarizing ideas, using formal tone, and explaining thinking clearly.'],
      9:['paragraph writing','A strong academic paragraph has a topic sentence, supporting details, evidence or examples, and a concluding sentence.'],
      10:['data description','When describing data, writers highlight major trends, compare important values, and avoid unsupported claims.'],
      11:['academic email','Academic email includes a clear subject, polite greeting, specific purpose, reasonable request, and respectful closing.'],
      12:['citation and ethics','Academic integrity requires students to credit sources, paraphrase carefully, quote accurately, and use AI transparently.'],
      13:['academic listening','Academic listeners focus on keywords, signal words, main points, and repeated ideas rather than every word.'],
      14:['academic presentation','A clear presentation includes an opening, outline, signposting, evidence, conclusion, and polite Q&A responses.'],
      15:['problem-solution presentation','A final academic presentation explains a social problem, causes, evidence, practical solutions, and a conclusion.']
    };
    const data = topicMap[s.id] || ['academic English', s.skill];
    return { topic:data[0], passage:data[1] };
  }

