    function aiHelpButtonLabel(skill, sessionId){
    const used = aiUsesFor(sessionId, skill);
    const limit = adaptiveAIHelpLimit(skill);
    const next = used < limit ? aiHelpStageLabel(used + 1, limit) : 'Limit reached';
    return `Ask AI Mentor (${Math.min(used + 1, limit)}/${limit}) • ${next}`;
  }
  function adaptiveAIHelpLabel(skill){
    const d = currentSkillDifficulty().key || 'easy';
    const limit = adaptiveAIHelpLimit(skill);
    if(d === 'challenge') return `${limit}/${limit} Challenge`;
    if(d === 'hard') return `${limit}/${limit} Hard Boss Gate 1+`;
    if(d === 'easy') return `${limit}/${limit} Easy A2`;
    return `${limit}/${limit} Normal Boss Gate 1`;
  }

  function aiHelpStageLabel(useNo, limit){
    if(limit >= 3){
      if(useNo === 1) return 'Hint';
      if(useNo === 2) return 'Draft feedback';
      return 'Sentence frame / checklist';
    }
    if(limit === 2){
      return useNo === 1 ? 'Hint' : 'Frame / checklist';
    }
    return 'One careful hint';
  }

  function adaptiveAIPenalty(uses, skill){
    const d = currentSkillDifficulty().key || 'easy';
    uses = Number(uses || 0);
    if(uses <= 0) return 0;
    if(d === 'easy') return Math.max(0, uses - 2) * 2;
    if(d === 'normal') return Math.max(0, uses - 1) * 3;
    if(d === 'hard') return uses * 5;
    return uses * 8;
  }


  function aiPenaltyForSkillLevel(skill, sessionId){
    const uses = aiUsesFor(sessionId, skill);
    return adaptiveAIPenalty(uses, skill);
  }


  function cefrSimplifyTask(text){
    return String(text || '')
      .replace(/\bevaluate\b/gi, 'check')
      .replace(/\bsynthesize\b/gi, 'combine')
      .replace(/\binfer\b/gi, 'guess from the text')
      .replace(/\bimplication\b/gi, 'meaning')
      .replace(/\blimitation\b/gi, 'weak point')
      .replace(/\bcredibility\b/gi, 'trust')
      .replace(/\bcautious academic language\b/gi, 'careful academic words')
      .replace(/\bclaim\b/gi, 'main idea')
      .replace(/\bevidence\b/gi, 'example or support');
  }

  function cefrScoreFloor(skill, score, output){
    const words = String(output || '').split(/\s+/).filter(Boolean).length;
    let bonus = 0;
    if(skill === 'Reading' && words >= 8) bonus = 10;
    if(skill === 'Writing' && words >= 25) bonus = 12;
    if(skill === 'Listening' && words >= 15) bonus = 12;
    if(skill === 'Speaking' && words >= 10) bonus = 8;
    return Math.min(100, Math.max(score, score + bonus));
  }

  const SKILL_DIFFICULTIES = {
    easy:{ key:'easy', label:'Easy A2', note:'คำถามสั้น มีกรอบช่วย เหมาะกับเริ่มต้น', aiLimitBonus:1, transcriptPenalty:3, scoreBonus:5 },
    normal:{ key:'normal', label:'Normal Boss Gate 1', note:'ระดับมาตรฐานของปี 2 ตอบสั้นแต่มีเหตุผล', aiLimitBonus:0, transcriptPenalty:6, scoreBonus:0 },
    hard:{ key:'hard', label:'Hard Boss Gate 1+', note:'ต้องอธิบายเหตุผลและหลักฐานมากขึ้น', aiLimitBonus:0, transcriptPenalty:9, scoreBonus:8 },
    challenge:{ key:'challenge', label:'Challenge Optional', note:'สำหรับโบนัส/เด็กพร้อม ไม่ใช่ค่าเริ่มต้น', aiLimitBonus:-1, transcriptPenalty:12, scoreBonus:15 }
  };

  function currentSkillDifficulty(){
    const key = state.settings?.skillDifficulty || state.settings?.difficulty || 'normal';
    return SKILL_DIFFICULTIES[key] || SKILL_DIFFICULTIES.normal;
  }

  function setSkillDifficulty(level){
    if(!SKILL_DIFFICULTIES[level]) level = 'normal';
    state.settings = state.settings || {};
    state.settings.skillDifficulty = level;
    saveState();
    updateDifficultyUI(level);
    safeToast(`Selected difficulty: ${SKILL_DIFFICULTIES[level].label}`);
  }

  function updateDifficultyUI(level){
    const selected = SKILL_DIFFICULTIES[level] || SKILL_DIFFICULTIES.normal;

    document.querySelectorAll('[data-difficulty-card]').forEach(card => {
      const key = card.getAttribute('data-difficulty-card');
      const isSelected = key === level;
      card.classList.toggle('selected', isSelected);
      card.classList.toggle('ok', isSelected);
      const icon = card.querySelector('[data-difficulty-icon]');
      if(icon) icon.textContent = isSelected ? '✅' : '⬜';
      const btn = card.querySelector('[data-difficulty-button]');
      if(btn){
        btn.classList.toggle('success', isSelected);
        btn.classList.toggle('primary', !isSelected);
        btn.textContent = isSelected ? `Selected: ${selected.label}` : `Use ${SKILL_DIFFICULTIES[key]?.label || key}`;
      }
    });

    document.querySelectorAll('[data-current-difficulty]').forEach(el => {
      el.textContent = selected.label;
    });
    const rule = document.getElementById('currentDifficultyRule');
    if(rule){
      rule.innerHTML = `<h3>Current Rule: ${safe(selected.label)}</h3>
        <p><b>ตอนนี้เลือกอยู่:</b> ${safe(selected.label)} — ${safe(selected.note)}</p>
        <p class="mini-note">Hard/Challenge เพิ่มคะแนน bonus เล็กน้อย แต่โจทย์จะคาดหวัง evidence, inference, limitation และ academic tone มากขึ้น</p>`;
    }
  }

  function difficultyPromptAddon(skill){
    const d = currentSkillDifficulty().key;
    const map = {
      easy:{
        Reading:'Answer directly. Focus on main idea, keywords, and one support.',
        Writing:'Use the paragraph frame. Keep ideas clear and simple.',
        Listening:'Write main point, keywords, and one example.',
        Speaking:'Use opening, one reason, and closing.'
      },
      normal:{
        Reading:'Separate main idea, support, and one limitation.',
        Writing:'Include topic sentence, evidence/reason, and conclusion.',
        Listening:'Organize notes by main point, evidence, signal words, question.',
        Speaking:'Use signposting and one clear evidence/example.'
      },
      hard:{
        Reading:'Infer purpose/stance and evaluate evidence quality.',
        Writing:'Add cautious language, limitation, and stronger academic support.',
        Listening:'Identify idea and example relationship and missing information.',
        Speaking:'Include claim, evidence, limitation, and Q&A readiness.'
      },
      challenge:{
        Reading:'Evaluate source credibility, claim strength, limitation, and cautious rewrite.',
        Writing:'Produce a polished academic response with synthesis/ethics/limitation.',
        Listening:'Create structured notes plus summary, implication, and follow-up question.',
        Speaking:'Deliver a defendable mini-presentation with evidence, limitation, and response to challenge.'
      }
    };
    return map[d]?.[skill] || '';
  }

  function difficultyAdjustedScore(score){
    const d = currentSkillDifficulty();
    return Math.max(0, Math.min(100, Number(score || 0) + (d.scoreBonus || 0)));
  }

